from typing import List

def solve(nums: List[int]) -> int:
    n = len(nums)
    left_sum = 0
    right_product = 1

    for i in range(n):
        if i == 0:
            # Check if the first element is a balance index
            if left_sum == right_product:
                return 0
        else:
            # Update left sum and check balance
            left_sum += nums[i-1]
            if left_sum == right_product:
                return i

        # Update right product
        right_product *= nums[i]

    return -1
